import { Injectable, inject } from '@angular/core';
import { SupabaseService } from '../Base/supabase.service';
import { AuthService } from '../Base/auth.service';
import { BehaviorSubject } from 'rxjs';
import { ReservationService } from '../Prenotazioni/reservation.service';

export interface TableAssignment {
  reservationId: string;
  tableId: string;
  customerName: string;
  partySize: number;
  reservationTime: string;
  assignedAt: Date;
}

@Injectable({
  providedIn: 'root'
})
export class FloorManagementService {
  private supabaseService = inject(SupabaseService);
  private authService = inject(AuthService);
  private reservationService = inject(ReservationService);

  // RIPRISTINA IL BEHAVIORSUBJECT PER LO STATO LOCALE
  private todaysReservationsSubject = new BehaviorSubject<any[]>([]);
  public todaysReservations$ = this.todaysReservationsSubject.asObservable();

  // Carica tutte le prenotazioni di oggi
async loadTodaysReservations(): Promise<void> {
  try {
    const restaurantId = await this.getCurrentRestaurantId();
    console.log('🔍 Restaurant ID per prenotazioni:', restaurantId);

    const today = new Date().toISOString().split('T')[0];
    console.log('📅 Data di oggi per query:', today);

    const { data, error } = await this.supabaseService.getSupabaseClient()
      .from('reservations')
      .select('*')
      .eq('restaurant_id', restaurantId)
      .eq('reservation_date', today)
      .in('status', ['confirmed', 'pending'])
      .order('reservation_time', { ascending: true });

    if (error) {
      console.error('❌ Errore query prenotazioni:', error);
      throw error;
    }

    console.log('📋 Prenotazioni caricate dal DB:', {
      totale: data?.length || 0,
      conTavolo: data?.filter(r => r.table_id)?.length || 0,
      senzaTavolo: data?.filter(r => !r.table_id)?.length || 0
    });

    this.todaysReservationsSubject.next(data || []);
  } catch (error) {
    console.error('❌ Errore caricamento prenotazioni:', error);
    this.todaysReservationsSubject.next([]);
  }
}

  // Assegna un tavolo a una prenotazione
async assignTableToReservation(reservationId: string, tableId: string): Promise<boolean> {
  try {
    const success = await this.reservationService.assignTableToReservation(reservationId, tableId);
    
    // ✅ QUESTA È LA CHIAVE: Ricarica le prenotazioni DOPO l'assegnazione
    if (success) {
      await this.loadTodaysReservations(); // ← Questo aggiorna todaysReservationsSubject
    }
    
    return success;
  } catch (error) {
    console.error('❌ Error assigning table to reservation:', error);
    return false;
  }
}


  // Rimuovi assegnazione tavolo
  async removeTableAssignment(reservationId: string): Promise<boolean> {
    try {
      const success = await this.reservationService.removeTableFromReservation(reservationId);
      
      // Dopo aver rimosso l'assegnazione, ricarica le prenotazioni
      if (success) {
        await this.loadTodaysReservations();
      }
      
      return success;
    } catch (error) {
      console.error('❌ Error removing table assignment:', error);
      return false;
    }
  }

  // Ottieni prenotazioni senza tavolo assegnato
  getReservationsWithoutTable(): any[] {
    return this.todaysReservationsSubject.value.filter(r => !r.table_id);
  }

  // Ottieni prenotazioni con tavolo assegnato
  getReservationsWithTable(): any[] {
    return this.todaysReservationsSubject.value.filter(r => r.table_id);
  }

  // Metodo pubblico per ottenere le prenotazioni correnti
  getCurrentReservations(): any[] {
    return this.todaysReservationsSubject.value;
  }

  // Suggerisci tavoli disponibili per una prenotazione
  async suggestTablesForReservation(reservationId: string, partySize: number): Promise<any[]> {
    try {
      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) return [];

      // Ottieni la prenotazione specifica
      const reservations = this.getCurrentReservations();
      const reservation = reservations.find(r => r.id === reservationId);
      
      if (!reservation) return [];

      // Ottieni tutti i tavoli del ristorante
      const { data: allTables, error: tablesError } = await this.supabaseService.getSupabaseClient()
        .from('tables')
        .select('*')
        .eq('restaurant_id', restaurantId)
        .eq('is_active', true)
        .gte('capacity', partySize) // Tavoli con capacità sufficiente
        .order('capacity', { ascending: true });

      if (tablesError) throw tablesError;

      // Ottieni le prenotazioni di oggi per verificare la disponibilità
      const today = new Date().toISOString().split('T')[0];
      const todaysReservations = reservations.filter(r => 
        r.reservation_date === today && 
        ['confirmed', 'pending'].includes(r.status)
      );

      // Filtra tavoli disponibili
      const reservedTableIds = todaysReservations
        .map(r => r.table_id)
        .filter(id => id !== null && id !== reservation.table_id); // Escludi il tavolo attuale se già assegnato

      const availableTables = allTables?.filter(table => 
        !reservedTableIds.includes(table.id)
      ) || [];

      return availableTables;
    } catch (error) {
      console.error('❌ Error suggesting tables:', error);
      return [];
    }
  }

  // AGGIUNGI QUESTO METODO PER DEBUG
  async debugReservations(): Promise<void> {
    const today = new Date().toISOString().split('T')[0];
    console.log('🔍 DEBUG - Data di oggi:', today);
    console.log('🔍 DEBUG - Prenotazioni caricate:', this.todaysReservationsSubject.value);
    console.log('🔍 DEBUG - Prenotazioni senza tavolo:', this.getReservationsWithoutTable());
  }

  private async getCurrentRestaurantId(): Promise<string | null> {
    try {
      const user = this.authService.currentUserValue;
      if (!user) return null;

      // Se l'utente è staff, ottieni il restaurant_id dallo staff
      const staffRestaurantId = this.authService.getCurrentStaffRestaurantId();
      if (staffRestaurantId) {
        return staffRestaurantId;
      }

      // Altrimenti, cerca il ristorante di cui è owner
      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from('restaurants')
        .select('id')
        .eq('owner_id', user.id)
        .limit(1)
        .single();

      if (error) {
        console.error('Error getting restaurant by owner:', error);
        return null;
      }
      
      return data?.id || null;
    } catch (error) {
      console.error('Exception getting restaurant:', error);
      return null;
    }
  }


  async suggestTablesGroupedByFloorPlan(reservationId: string, partySize: number): Promise<{ floorPlan: any, tables: any[] }[]> {
  try {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) return [];

    // Ottieni la prenotazione specifica
    const reservations = this.getCurrentReservations();
    const reservation = reservations.find(r => r.id === reservationId);
    
    if (!reservation) return [];

    // Ottieni tutti i tavoli del ristorante CON le mappe
    const { data: allTables, error: tablesError } = await this.supabaseService.getSupabaseClient()
      .from('tables')
      .select(`
        *,
        floor_plans!inner (
          id,
          name
        )
      `)
      .eq('restaurant_id', restaurantId)
      .eq('is_active', true)
      .gte('capacity', partySize)
      .order('capacity', { ascending: true });

    if (tablesError) throw tablesError;

    // Ottieni le prenotazioni di oggi per verificare la disponibilità
    const today = new Date().toISOString().split('T')[0];
    const todaysReservations = reservations.filter(r => 
      r.reservation_date === today && 
      ['confirmed', 'pending'].includes(r.status)
    );

    // Filtra tavoli disponibili
    const reservedTableIds = todaysReservations
      .map(r => r.table_id)
      .filter(id => id !== null && id !== reservation.table_id);

    const availableTables = allTables?.filter(table => 
      !reservedTableIds.includes(table.id)
    ) || [];

    // Raggruppa i tavoli per mappa
    const groupedByFloorPlan: { [key: string]: any } = {};
    
    availableTables.forEach(table => {
      const floorPlanId = table.floor_plan_id || 'no-floor-plan';
      const floorPlanName = table.floor_plans?.name || 'Senza mappa';
      
      if (!groupedByFloorPlan[floorPlanId]) {
        groupedByFloorPlan[floorPlanId] = {
          floorPlan: {
            id: floorPlanId,
            name: floorPlanName
          },
          tables: []
        };
      }
      
      groupedByFloorPlan[floorPlanId].tables.push(table);
    });

    // Converti in array
    return Object.values(groupedByFloorPlan);

  } catch (error) {
    console.error('❌ Error suggesting grouped tables:', error);
    return [];
  }
}

async getAllTablesGroupedByFloorPlan(): Promise<{ floorPlan: any, tables: any[] }[]> {
  try {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) return [];

    // Usa la tabella CORRETTA: restaurant_floor_plans
    const { data: allTables, error: tablesError } = await this.supabaseService.getSupabaseClient()
      .from('tables')
      .select(`
        *,
        restaurant_floor_plans (
          id,
          name
        )
      `) // CAMBIA: restaurant_floor_plans
      .eq('restaurant_id', restaurantId)
      .eq('is_active', true)
      .order('table_number', { ascending: true });

    if (tablesError) throw tablesError;

    // DEBUG per vedere la struttura
    console.log('🔍 Struttura dati:', allTables?.slice(0, 1));

    // Raggruppa i tavoli per mappa
    const groupedByFloorPlan: { [key: string]: any } = {};
    
    allTables?.forEach(table => {
      const floorPlanId = table.floor_plan_id || 'no-floor-plan';
      
      // CORREZIONE: restaurant_floor_plans è un array
      let floorPlanName = 'Senza mappa';
      
      if (table.restaurant_floor_plans) {
        if (Array.isArray(table.restaurant_floor_plans) && table.restaurant_floor_plans.length > 0) {
          floorPlanName = table.restaurant_floor_plans[0].name;
        } else if (table.restaurant_floor_plans.name) {
          // Fallback
          floorPlanName = table.restaurant_floor_plans.name;
        }
      }
      
      if (!groupedByFloorPlan[floorPlanId]) {
        groupedByFloorPlan[floorPlanId] = {
          floorPlan: {
            id: floorPlanId,
            name: floorPlanName
          },
          tables: []
        };
      }
      
      groupedByFloorPlan[floorPlanId].tables.push(table);
    });

    // Converti in array e ordina
    const result = Object.values(groupedByFloorPlan);
    result.sort((a, b) => {
      if (a.floorPlan.id === 'no-floor-plan') return 1;
      if (b.floorPlan.id === 'no-floor-plan') return -1;
      return a.floorPlan.name.localeCompare(b.floorPlan.name);
    });

    console.log('✅ Tavoli raggruppati:', result);
    return result;

  } catch (error) {
    console.error('❌ Error getting all tables grouped by floor plan:', error);
    return [];
  }
}

// Metodo per ottenere tavoli disponibili (filtro aggiuntivo)
async getAvailableTablesGroupedByFloorPlan(reservationDateTime?: string): Promise<{ floorPlan: any, tables: any[] }[]> {
  try {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) return [];

    // Carica le prenotazioni di oggi
    await this.loadTodaysReservations();
    const todaysReservations = this.getCurrentReservations();

    // Ottieni tutti i tavoli con le mappe
    const allTablesGrouped = await this.getAllTablesGroupedByFloorPlan();
    
    // Filtra i tavoli già occupati per l'orario specificato (se fornito)
    if (reservationDateTime) {
      // Logica per verificare quali tavoli sono già occupati all'orario specificato
      // (Da implementare in base alla tua logica di business)
    }

    return allTablesGrouped;

  } catch (error) {
    console.error('❌ Error getting available tables grouped by floor plan:', error);
    return [];
  }
}

}